const checkpoints = [];

const products = JSON.parse(localStorage.getItem('products') || '[]');
const carts = JSON.parse(localStorage.getItem('carts') || '[]');
const cartItemsAll = JSON.parse(localStorage.getItem('cart_items') || '[]');

// Use runtime cart (ignore pre-seeded task carts)
const runtimeCart = carts.find(c => c.status === 'open' && c.id && !c.id.startsWith('cart_task')) || null;

let qualifyingSubs = [];
let cheapestQualifyingSubs = [];

if (runtimeCart) {
  const subs = cartItemsAll.filter(ci => ci.cart_id === runtimeCart.id && ci.item_type === 'subscription');

  // All 5-gallon spring water products under $15
  const spring5gUnderMax = products.filter(p => 
    p.category_id === 'water' &&
    p.water_type === 'spring' &&
    p.size_filter_key === '5_gallon' &&
    p.status === 'active' &&
    typeof p.price === 'number' &&
    p.price <= 15
  );

  let cheapestPrice = null;
  spring5gUnderMax.forEach(p => {
    if (cheapestPrice === null || p.price < cheapestPrice) cheapestPrice = p.price;
  });
  const cheapestProducts = spring5gUnderMax.filter(p => p.price === cheapestPrice);

  subs.forEach(ci => {
    const prod = products.find(p => p.id === ci.product_id);
    if (!prod) return;
    const isCorrectProduct = prod.category_id === 'water' && prod.water_type === 'spring' && prod.size_filter_key === '5_gallon' && typeof prod.price === 'number' && prod.price <= 15;
    const isCorrectConfig = ci.quantity === 2 && ci.subscription_frequency === 'every_week' && ci.subscription_delivery_day_of_week === 'monday';
    if (isCorrectProduct && isCorrectConfig) {
      qualifyingSubs.push(ci);
      if (cheapestProducts.some(p => p.id === ci.product_id)) {
        cheapestQualifyingSubs.push(ci);
      }
    }
  });
}

// CP1 (0.4): Cart has a qualifying weekly Monday subscription for 2 units of a 5-gallon spring water under $15
checkpoints.push({ passed: qualifyingSubs.length > 0, weight: 0.4 });

// CP2 (0.6): That subscription uses the cheapest qualifying 5-gallon spring water product under $15
checkpoints.push({ passed: cheapestQualifyingSubs.length > 0, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const products = JSON.parse(localStorage.getItem('products') || '[]');
const orders = JSON.parse(localStorage.getItem('orders') || '[]');
const orderItemsAll = JSON.parse(localStorage.getItem('order_items') || '[]');

// Only consider runtime orders (ids generated at runtime, not pre-seeded task orders)
const runtimeOrders = orders.filter(o => o.id && o.id.startsWith('order_'));

let hasOrderWith1Size = false;
let hasOrderWith2Sizes = false;
let hasPerfectOrder = false;

runtimeOrders.forEach(order => {
  const items = orderItemsAll.filter(oi => oi.order_id === order.id && oi.item_type === 'one_time');
  const sizeCounts = { '500_ml': 0, '1_l': 0, '5_l': 0 };

  const sparklingCaseItems = items.filter(oi => {
    const prod = products.find(p => p.id === oi.product_id);
    return !!prod &&
      prod.category_id === 'water' &&
      prod.water_type === 'sparkling' &&
      prod.is_case === true &&
      typeof prod.price === 'number' && prod.price < 12 &&
      ['500_ml', '1_l', '5_l'].includes(prod.size_filter_key);
  });

  sparklingCaseItems.forEach(oi => {
    const prod = products.find(p => p.id === oi.product_id);
    if (!prod) return;
    const size = prod.size_filter_key;
    sizeCounts[size] += oi.quantity || 0;
  });

  const reqSizes = ['500_ml', '1_l', '5_l'];
  const presentReqSizes = reqSizes.filter(s => sizeCounts[s] > 0);

  if (presentReqSizes.length >= 1) {
    hasOrderWith1Size = true;
  }
  if (presentReqSizes.length >= 2) {
    hasOrderWith2Sizes = true;
  }

  const allThreePresentOnce = presentReqSizes.length === 3 &&
    sizeCounts['500_ml'] === 1 &&
    sizeCounts['1_l'] === 1 &&
    sizeCounts['5_l'] === 1 &&
    sparklingCaseItems.length === 3 &&
    sparklingCaseItems.every(oi => oi.quantity === 1);

  const orderIsOneTimeOnly = order.contains_subscriptions === false && order.contains_rentals === false;

  if (allThreePresentOnce && orderIsOneTimeOnly) {
    hasPerfectOrder = true;
  }
});

// CP1 (0.2): Some runtime order has at least one qualifying sparkling case size under $12
checkpoints.push({ passed: hasOrderWith1Size, weight: 0.2 });

// CP2 (0.3): Some runtime order has at least two of the required distinct case sizes (500 ml, 1 L, 5 L) under $12
checkpoints.push({ passed: hasOrderWith2Sizes, weight: 0.3 });

// CP3 (0.5): Some runtime order has exactly one 500 ml, one 1 L, and one 5 L sparkling case (all under $12, quantity 1 each) and is one-time only
checkpoints.push({ passed: hasPerfectOrder, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const products = JSON.parse(localStorage.getItem('products') || '[]');
const carts = JSON.parse(localStorage.getItem('carts') || '[]');
const cartItemsAll = JSON.parse(localStorage.getItem('cart_items') || '[]');
const orders = JSON.parse(localStorage.getItem('orders') || '[]');
const orderItemsAll = JSON.parse(localStorage.getItem('order_items') || '[]');
const promos = JSON.parse(localStorage.getItem('promos') || '[]');

// Highest-percentage promo that applies to one-time orders (directly or via all_orders)
const percentagePromos = promos.filter(p => 
  p.status === 'active' &&
  p.discount_type === 'percentage' &&
  (p.applicable_order_type === 'one_time_orders' || p.applicable_order_type === 'all_orders')
);
let bestPercent = null;
percentagePromos.forEach(p => {
  if (bestPercent === null || p.discount_value > bestPercent) bestPercent = p.discount_value;
});
const bestPromos = percentagePromos.filter(p => p.discount_value === bestPercent);
const bestPromoCodes = new Set(bestPromos.map(p => p.code.toLowerCase()));
const bestPromoIds = new Set(bestPromos.map(p => p.id));

let hasBestPromo = false;
let hasBestPromoPlusSomeCases = false;
let hasBestPromoPlusThreeCases = false;

function evaluateCart(cart) {
  const appliedPromo = cart.applied_promo_id ? promos.find(p => p.id === cart.applied_promo_id) : null;
  const promoIsBest = !!(appliedPromo && bestPromoCodes.has(appliedPromo.code.toLowerCase()));

  const items = cartItemsAll.filter(ci => ci.cart_id === cart.id && ci.item_type === 'one_time');
  let quantityCases = 0;

  items.forEach(ci => {
    const prod = products.find(p => p.id === ci.product_id);
    if (!prod) return;
    const isTargetCase = prod.category_id === 'water' &&
      prod.water_type === 'still' &&
      prod.is_case === true &&
      prod.size_filter_key === '1_l' &&
      prod.case_bottle_count === 12;
    if (isTargetCase) {
      quantityCases += ci.quantity || 0;
    }
  });

  if (promoIsBest) {
    hasBestPromo = true;
    if (quantityCases >= 1) hasBestPromoPlusSomeCases = true;
    if (quantityCases >= 3) hasBestPromoPlusThreeCases = true;
  }
}

function evaluateOrder(order) {
  const promoCode = order.promo_code || '';
  const promoIsBest = promoCode && bestPromoCodes.has(promoCode.toLowerCase());

  const items = orderItemsAll.filter(oi => oi.order_id === order.id && oi.item_type === 'one_time');
  let quantityCases = 0;

  items.forEach(oi => {
    const prod = products.find(p => p.id === oi.product_id);
    if (!prod) return;
    const isTargetCase = prod.category_id === 'water' &&
      prod.water_type === 'still' &&
      prod.is_case === true &&
      prod.size_filter_key === '1_l' &&
      prod.case_bottle_count === 12;
    if (isTargetCase) {
      quantityCases += oi.quantity || 0;
    }
  });

  if (promoIsBest) {
    hasBestPromo = true;
    if (quantityCases >= 1) hasBestPromoPlusSomeCases = true;
    if (quantityCases >= 3) hasBestPromoPlusThreeCases = true;
  }
}

// Runtime carts: ids generated by BusinessLogic (exclude pre-seeded task carts)
const runtimeCarts = carts.filter(c => c.id && c.id.startsWith('cart_'));
runtimeCarts.forEach(evaluateCart);

// Runtime orders: ids generated at runtime (exclude pre-seeded task orders)
const runtimeOrders = orders.filter(o => o.id && o.id.startsWith('order_'));
runtimeOrders.forEach(evaluateOrder);

// CP1 (0.4): User applied the highest-percentage promo applicable to one-time orders on some runtime cart/order
checkpoints.push({ passed: hasBestPromo, weight: 0.4 });

// CP2 (0.2): That best promo is applied where at least one qualifying 1 L still 12-bottle case is present
checkpoints.push({ passed: hasBestPromoPlusSomeCases, weight: 0.2 });

// CP3 (0.4): That best promo is applied where at least three such cases are in a single cart/order
checkpoints.push({ passed: hasBestPromoPlusThreeCases, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const subscriptions = JSON.parse(localStorage.getItem('subscriptions') || '[]');

// Identify the first active weekly subscription as defined in initial data
const targetSub = subscriptions.find(s => s.id === 'sub_crystal5g_home_weekly') || null;

let freqUpdated = false;
let dayAndQtyUpdated = false;

if (targetSub) {
  // CP1 condition: frequency changed to every_2_weeks and status still active
  freqUpdated = (targetSub.subscription_frequency === 'every_2_weeks' && targetSub.status === 'active');

  // CP2 condition: delivery day changed to Wednesday and quantity is 3, with status active
  dayAndQtyUpdated = (targetSub.delivery_day_of_week === 'wednesday' && targetSub.quantity === 3 && targetSub.status === 'active');
}

// CP1 (0.5): Target subscription now delivers every 2 weeks (and is active)
checkpoints.push({ passed: freqUpdated, weight: 0.5 });

// CP2 (0.5): Target subscription now has quantity 3 and delivers on Wednesday (and is active)
checkpoints.push({ passed: dayAndQtyUpdated, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const addresses = JSON.parse(localStorage.getItem('addresses') || '[]');
const deliveries = JSON.parse(localStorage.getItem('deliveries') || '[]');

// New address details
const newAddr = addresses.find(a => 
  a.street === '123 Oak Street' &&
  a.city === 'Springfield' &&
  a.state === 'CA' &&
  a.zip_code === '12345'
) || null;

const hasCorrectNewAddress = !!(newAddr && typeof newAddr.label === 'string' && newAddr.label.toLowerCase() === 'home');

// Compute the 15th of next month based on current date
const today = new Date();
const thisMonth = today.getMonth();
const thisYear = today.getFullYear();
const nextMonthIndex = (thisMonth + 1) % 12;
const yearForNextMonth = thisMonth === 11 ? thisYear + 1 : thisYear;
// Use UTC to make date comparison stable
const targetDateObj = new Date(Date.UTC(yearForNextMonth, nextMonthIndex, 15));
const targetDateStr = targetDateObj.toISOString().slice(0, 10);

let hasRescheduledDelivery = false;

if (newAddr) {
  // Look for a delivery that has been rescheduled (status 'rescheduled') to this new address
  const rescheduledDeliveries = deliveries.filter(d => d.status === 'rescheduled');

  hasRescheduledDelivery = rescheduledDeliveries.some(d => {
    if (d.address_id !== newAddr.id) return false;
    if (d.time_window !== '15_00_18_00') return false;
    if (d.delivery_method !== 'standard') return false;
    if (typeof d.scheduled_date !== 'string') return false;
    const datePart = d.scheduled_date.slice(0, 10);
    return datePart === targetDateStr;
  });
}

// CP1 (0.4): New Home address at 123 Oak Street, Springfield, CA 12345 exists
checkpoints.push({ passed: hasCorrectNewAddress, weight: 0.4 });

// CP2 (0.6): At least one delivery was rescheduled to that new address on the 15th of next month, 3–6 PM, with standard delivery
checkpoints.push({ passed: hasRescheduledDelivery, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const products = JSON.parse(localStorage.getItem('products') || '[]');
const carts = JSON.parse(localStorage.getItem('carts') || '[]');
const cartItemsAll = JSON.parse(localStorage.getItem('cart_items') || '[]');

// Runtime cart (ignore pre-seeded task carts)
const runtimeCart = carts.find(c => c.status === 'open' && c.id && !c.id.startsWith('cart_task')) || null;

let hasEcoRecycledCase = false;
let hasEco5GallonJug = false;

if (runtimeCart) {
  const items = cartItemsAll.filter(ci => ci.cart_id === runtimeCart.id && ci.item_type === 'one_time');

  // Qualifying eco-friendly products per criteria
  const recycledCaseIds = new Set(
    products
      .filter(p => 
        p.category_id === 'water' &&
        p.is_eco_friendly === true &&
        typeof p.rating === 'number' && p.rating >= 4.5 &&
        typeof p.price === 'number' && p.price >= 5 && p.price <= 25 &&
        p.packaging_category === 'bottled_cases' &&
        (
          (Array.isArray(p.tags) && p.tags.some(t => t.toLowerCase().includes('recycled'))) ||
          (Array.isArray(p.badges) && p.badges.some(b => b.toLowerCase().includes('recycled')))
        )
      )
      .map(p => p.id)
  );

  const ecoJugIds = new Set(
    products
      .filter(p => 
        p.category_id === 'water' &&
        p.is_eco_friendly === true &&
        typeof p.rating === 'number' && p.rating >= 4.5 &&
        typeof p.price === 'number' && p.price >= 5 && p.price <= 25 &&
        p.packaging_category === 'refillable_jugs' &&
        p.size_filter_key === '5_gallon'
      )
      .map(p => p.id)
  );

  items.forEach(ci => {
    const pid = ci.product_id;
    if (recycledCaseIds.has(pid) && (ci.quantity || 0) >= 1) {
      hasEcoRecycledCase = true;
    }
    if (ecoJugIds.has(pid) && (ci.quantity || 0) >= 1) {
      hasEco5GallonJug = true;
    }
  });
}

// CP1 (0.3): Cart has at least one qualifying eco-friendly recycled-packaging bottled case (one-time)
checkpoints.push({ passed: hasEcoRecycledCase, weight: 0.3 });

// CP2 (0.3): Cart has at least one qualifying eco-friendly 5-gallon refillable jug (one-time)
checkpoints.push({ passed: hasEco5GallonJug, weight: 0.3 });

// CP3 (0.4): Cart has both qualifying items (one recycled case and one 5-gallon jug)
checkpoints.push({ passed: hasEcoRecycledCase && hasEco5GallonJug, weight: 0.4 });

return checkoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const searchQueryRaw = localStorage.getItem('task7_helpSearchQuery');
const articleSlug = localStorage.getItem('task7_minOrderArticleSlug');
const helpArticles = JSON.parse(localStorage.getItem('help_articles') || '[]');
const siteSettingsArr = JSON.parse(localStorage.getItem('site_settings') || '[]');
const carts = JSON.parse(localStorage.getItem('carts') || '[]');
const cartItemsAll = JSON.parse(localStorage.getItem('cart_items') || '[]');
const products = JSON.parse(localStorage.getItem('products') || '[]');

const settings = siteSettingsArr[0] || { minimum_order_amount: 30 };
const minOrder = typeof settings.minimum_order_amount === 'number' ? settings.minimum_order_amount : 30;

// ---- Help Center search & article open ----
let helpStepComplete = false;
if (searchQueryRaw && typeof searchQueryRaw === 'string') {
  const q = searchQueryRaw.toLowerCase();
  const queryLooksCorrect = q.includes('minimum') && q.includes('order') && q.includes('amount');
  const openedMinArticle = articleSlug === 'minimum-order-amount';
  helpStepComplete = queryLooksCorrect && openedMinArticle;
}

// ---- Cart & quantity adjustment ----
// Use runtime cart (ignore pre-seeded task carts)
const runtimeCart = carts.find(c => c.status === 'open' && c.id && !c.id.startsWith('cart_task')) || null;

let qtyAdjustedEnough = false;
let cartSubtotalEnough = false;

if (runtimeCart) {
  const items = cartItemsAll.filter(ci => ci.cart_id === runtimeCart.id);
  // consider first water product item in this cart
  const waterItems = items.filter(ci => {
    const prod = products.find(p => p.id === ci.product_id);
    return !!prod && prod.category_id === 'water';
  });

  if (waterItems.length > 0) {
    const mainItem = waterItems[0];
    const prod = products.find(p => p.id === mainItem.product_id);
    const price = prod && typeof prod.price === 'number' ? prod.price : mainItem.unit_price || 0;
    if (price > 0) {
      const neededQty = Math.ceil(minOrder / price);
      const qty = mainItem.quantity || 0;
      const lineSubtotal = qty * price;
      qtyAdjustedEnough = qty >= neededQty;
      cartSubtotalEnough = qtyAdjustedEnough && (runtimeCart.subtotal || 0) >= minOrder && lineSubtotal >= minOrder;
    }
  }
}

// CP1 (0.3): User searched for a query mentioning the minimum order amount and opened the correct article
checkpoints.push({ passed: helpStepComplete, weight: 0.3 });

// CP2 (0.3): Cart contains a water product whose quantity was increased to at least the amount implied by price and the minimum order amount
checkpoints.push({ passed: qtyAdjustedEnough, weight: 0.3 });

// CP3 (0.4): That quantity adjustment results in the cart subtotal and that line subtotal meeting or exceeding the minimum order amount
checkpoints.push({ passed: cartSubtotalEnough, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const products = JSON.parse(localStorage.getItem('products') || '[]');
const orders = JSON.parse(localStorage.getItem('orders') || '[]');
const orderItemsAll = JSON.parse(localStorage.getItem('order_items') || '[]');
const deliveries = JSON.parse(localStorage.getItem('deliveries') || '[]');
const siteSettingsArr = JSON.parse(localStorage.getItem('site_settings') || '[]');

const settings = siteSettingsArr[0] || { max_delivery_schedule_days_ahead: 30 };
const maxWindowDays = typeof settings.max_delivery_schedule_days_ahead === 'number' ? settings.max_delivery_schedule_days_ahead : 30;

// Only consider runtime orders (exclude pre-seeded task orders like order_task8_...)
const runtimeOrders = orders.filter(o => o.id && o.id.startsWith('order_'));

let hasOrderWithRental = false;
let hasOrderWithRentalAndWater = false;
let hasFullOrderWithDelivery = false;

const today = new Date();
const sevenDaysLater = new Date(today.getTime());
sevenDaysLater.setDate(today.getDate() + 7);

runtimeOrders.forEach(order => {
  const items = orderItemsAll.filter(oi => oi.order_id === order.id);

  // Rental condition
  const rentalItems = items.filter(oi => oi.item_type === 'rental');
  let rentalOk = false;
  rentalItems.forEach(oi => {
    const prod = products.find(p => p.id === oi.product_id);
    if (!prod) return;
    const pricePerMonth = typeof prod.rental_price_per_month === 'number' ? prod.rental_price_per_month : oi.unit_price || 0;
    const isDispenserRental = prod.category_id === 'dispensers' && prod.is_rental_product === true;
    const durationOneMonth = oi.rental_duration === '1_month';
    if (isDispenserRental && pricePerMonth <= 20 && durationOneMonth && (oi.quantity || 0) >= 1) {
      rentalOk = true;
    }
  });

  if (!rentalOk) return;
  hasOrderWithRental = true;

  // Water items condition: four still 5-gallon bottles
  const waterItems = items.filter(oi => oi.item_type === 'one_time');
  let waterQuantity = 0;
  waterItems.forEach(oi => {
    const prod = products.find(p => p.id === oi.product_id);
    if (!prod) return;
    const isTargetWater = prod.category_id === 'water' &&
      prod.water_type === 'still' &&
      prod.size_filter_key === '5_gallon';
    if (isTargetWater) {
      waterQuantity += oi.quantity || 0;
    }
  });

  const waterOk = waterQuantity >= 4;
  if (!waterOk) return;
  hasOrderWithRentalAndWater = true;

  // Delivery condition: standard delivery within next 7 days
  const delivery = deliveries.find(d => d.id === order.delivery_id) || null;
  if (!delivery) return;
  if (delivery.delivery_method !== 'standard') return;
  if (typeof delivery.scheduled_date !== 'string') return;

  const schedDate = new Date(delivery.scheduled_date);
  if (Number.isNaN(schedDate.getTime())) return;

  const within7Days = schedDate >= today && schedDate <= sevenDaysLater;

  if (within7Days) {
    hasFullOrderWithDelivery = true;
  }
});

// CP1 (0.25): Some runtime order includes a dispenser rental product (rental) costing no more than $20 per month for a 1-month duration
checkpoints.push({ passed: hasOrderWithRental, weight: 0.25 });

// CP2 (0.35): Some runtime order includes that rental and at least four still 5-gallon water bottles as one-time items
checkpoints.push({ passed: hasOrderWithRentalAndWater, weight: 0.35 });

// CP3 (0.40): That same order has a standard delivery scheduled within the next 7 days
checkpoints.push({ passed: hasFullOrderWithDelivery, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
